-- CHECK
ALTER TABLE [INV].[PRODUCTOS] ADD CONSTRAINT [CHK_TIPO_PRODUCTO] CHECK ([TIPO_PRODUCTO]='ARTICULO_VARIO' OR [TIPO_PRODUCTO]='PERFUME');
GO
