GO
ALTER TABLE [INV].[PRODUCTOS] ADD CONSTRAINT [CHK_INV_PRECIO_POSITIVO] CHECK ([PRECIO_VENTA]>(0));
GO
ALTER TABLE [INV].[EQUIPOS_IMEI] ADD CONSTRAINT [CHK_ESTADO_IMEI] CHECK ([ESTADO_IMEI]='DANADO' OR [ESTADO_IMEI]='EN_GARANTIA' OR [ESTADO_IMEI]='DEVUELTO' OR [ESTADO_IMEI]='VENDIDO' OR [ESTADO_IMEI]='DISPONIBLE');
GO
ALTER TABLE [CAJA].[DENOMINACIONES] ADD CONSTRAINT [CHK_TIPO_DENOM] CHECK ([TIPO]='MONEDA' OR [TIPO]='BILLETE');
GO
ALTER TABLE [CAJA].[TURNOS] ADD CONSTRAINT [CHK_ESTADO_CUADRE] CHECK ([ESTADO_CUADRE]=NULL OR [ESTADO_CUADRE]='FALTANTE' OR [ESTADO_CUADRE]='SOBRANTE' OR [ESTADO_CUADRE]='EXACTO');
GO
