GO
ALTER TABLE [GAR].[GARANTIAS] ADD CONSTRAINT [CHK_GAR_ESTADO] CHECK ([ESTADO_GARANTIA]='CANCELADA' OR [ESTADO_GARANTIA]='VENCIDA' OR [ESTADO_GARANTIA]='USADA' OR [ESTADO_GARANTIA]='ACTIVA');
GO
ALTER TABLE [GAR].[RECLAMOS_GARANTIA] ADD CONSTRAINT [CHK_TIPO_RESOLUCION] CHECK ([TIPO_RESOLUCION]=NULL OR [TIPO_RESOLUCION]='SIN_COBERTURA' OR [TIPO_RESOLUCION]='DEVOLUCION_DINERO' OR [TIPO_RESOLUCION]='REEMPLAZO' OR [TIPO_RESOLUCION]='REPARACION');
