-- vistas
SET QUOTED_IDENTIFIER ON;
GO

CREATE VIEW VEN.V_HISTORIAL_VENTAS AS
SELECT 
    V.*,
    U.USERNAME AS CAJERO,
    COALESCE(P.NOMBRE_COMPLETO, 'CLIENTE GENERAL') AS CLIENTE,
    (V.TOTAL_NIO / V.TASA_CAMBIO_USD) AS TOTAL_USD
FROM VEN.VENTAS V
JOIN ADM.USUARIOS U ON V.ID_USUARIO = U.ID_USUARIO
LEFT JOIN ADM.PERSONAS P ON V.ID_PERSONA = P.ID_PERSONA;

GO
SET QUOTED_IDENTIFIER ON;
GO

CREATE VIEW VEN.V_VENTAS_POR_TURNO AS
SELECT 
    V.ID_VENTA AS IdVenta,
    V.NUMERO_FACTURA AS NumeroFactura,
    V.FECHA_VENTA AS FechaVenta,
    COALESCE(P.NOMBRE_COMPLETO, 'CLIENTE GENERAL') AS Cliente,
    V.TOTAL_NIO AS TotalNio,
    V.ANULADA AS Anulada,
    V.ID_TURNO,
    STUFF((
        SELECT ', ' + MP.NOMBRE
        FROM VEN.PAGOS PG 
        JOIN CAT.METODOS_PAGO MP ON PG.ID_METODO_PAGO = MP.ID_METODO 
        WHERE PG.ID_VENTA = V.ID_VENTA
        FOR XML PATH(''), TYPE).value('.', 'NVARCHAR(MAX)'), 1, 2, '') AS MetodoPago
FROM VEN.VENTAS V
LEFT JOIN ADM.PERSONAS P ON V.ID_PERSONA = P.ID_PERSONA;

GO
SET QUOTED_IDENTIFIER ON;
GO
CREATE VIEW CAJA.V_ESTADO_TURNO_ACTUAL AS
SELECT 
    T.*,
    U.USERNAME,
    (T.MONTO_INICIAL_NIO + T.TOTAL_EFECTIVO_NIO + ISNULL((SELECT SUM(MONTO) FROM CAJA.MOVIMIENTOS_VARIOS WHERE ID_TURNO = T.ID_TURNO AND ID_MONEDA = 1), 0)) AS SALDO_TEORICO_NIO,
    (T.MONTO_INICIAL_USD + T.TOTAL_EFECTIVO_USD + ISNULL((SELECT SUM(MONTO) FROM CAJA.MOVIMIENTOS_VARIOS WHERE ID_TURNO = T.ID_TURNO AND ID_MONEDA = 2), 0)) AS SALDO_TEORICO_USD
FROM CAJA.TURNOS T
JOIN ADM.USUARIOS U ON T.ID_USUARIO = U.ID_USUARIO
WHERE T.FECHA_CIERRE IS NULL;

