CREATE VIEW VEN.V_RESUMEN_VENTAS AS
SELECT
    V.ID_VENTA,
    V.NUMERO_FACTURA,
    V.FECHA_VENTA,
    P.NOMBRE_COMPLETO                   AS CLIENTE,
    U_EMP.NOMBRE_COMPLETO               AS CAJERO,
    V.SUBTOTAL_NIO,
    V.DESCUENTO_NIO,
    V.TOTAL_NIO,
    V.ANULADA,
    T.FECHA_APERTURA                    AS APERTURA_TURNO
FROM VEN.VENTAS        V
JOIN CAJA.TURNOS       T   ON T.ID_TURNO    = V.ID_TURNO
JOIN ADM.USUARIOS      U   ON U.ID_USUARIO  = V.ID_USUARIO
JOIN ADM.EMPLEADOS     E   ON E.ID_EMPLEADO = U.ID_EMPLEADO
JOIN ADM.PERSONAS      U_EMP ON U_EMP.ID_PERSONA = E.ID_PERSONA
LEFT JOIN ADM.PERSONAS P   ON P.ID_PERSONA  = V.ID_PERSONA;

