    PE.NOMBRE_COMPLETO      AS CAJERO,
    T.FECHA_APERTURA,
    T.FECHA_CIERRE,
    T.MONTO_INICIAL_NIO,
    T.TOTAL_VENTAS_NIO,
    T.TOTAL_EFECTIVO_NIO,
    T.TOTAL_EFECTIVO_USD,
    T.MONTO_CONTADO_NIO,
    T.DIFERENCIA_NIO,
    T.ESTADO_CUADRE,
    E.CODIGO                AS ESTADO
FROM CAJA.TURNOS       T
JOIN ADM.USUARIOS      U   ON U.ID_USUARIO  = T.ID_USUARIO
JOIN ADM.EMPLEADOS     EM  ON EM.ID_EMPLEADO= U.ID_EMPLEADO
JOIN ADM.PERSONAS      PE  ON PE.ID_PERSONA = EM.ID_PERSONA
JOIN CAT.ESTADOS       E   ON E.ID_ESTADO   = T.ID_ESTADO;

