CREATE PROCEDURE INV.sp_MantenerProducto
    @IdProducto INT = NULL,
    @CodigoBarras NVARCHAR(100) = NULL,
    @Nombre NVARCHAR(150),
    @Marca NVARCHAR(100) = NULL,
    @IdGenero INT = NULL,
    @IdOrigen INT = NULL,
    @IdConcentracion INT = NULL,
    @Ml DECIMAL(8,2) = NULL,
    @FechaVencimiento DATE = NULL,
    @IdCategoria INT = NULL,
    @TipoProducto VARCHAR(20) = 'PERFUME',
    @PrecioCompra DECIMAL(12,2) = NULL,
    @PrecioVenta DECIMAL(12,2),
    @StockActual INT = 0,
    @StockMinimo INT = 0,
    @Activo BIT = 1,
    @UsuarioId INT = NULL
AS
BEGIN
    SET NOCOUNT ON; SET XACT_ABORT ON;
    BEGIN TRANSACTION;
    
    SET @CodigoBarras = NULLIF(LTRIM(RTRIM(@CodigoBarras)), '');
    SET @Nombre = LTRIM(RTRIM(@Nombre));
    
    IF @TipoProducto NOT IN ('PERFUME', 'ARTICULO_VARIO')
        SET @TipoProducto = 'PERFUME';

    IF @CodigoBarras IS NOT NULL AND EXISTS (SELECT 1 FROM INV.PRODUCTOS WHERE CODIGO_BARRAS = @CodigoBarras AND (@IdProducto IS NULL OR ID_PRODUCTO <> @IdProducto))
        THROW 50001, 'El código de barras ya pertenece a otro producto.', 1;

    IF @IdProducto IS NULL OR @IdProducto = 0
    BEGIN
        INSERT INTO INV.PRODUCTOS (
            CODIGO_BARRAS, NOMBRE, MARCA, ID_GENERO, ID_ORIGEN, ID_CONCENTRACION, ML, FECHA_VENCIMIENTO, 
            ID_CATEGORIA, TIPO_PRODUCTO, PRECIO_COMPRA, PRECIO_VENTA, STOCK_ACTUAL, STOCK_MINIMO, ACTIVO, CREADO_POR, FECHA_DESACTIVACION
        )
        VALUES (
            @CodigoBarras, @Nombre, @Marca, @IdGenero, @IdOrigen, @IdConcentracion, @Ml, @FechaVencimiento, 
            @IdCategoria, @TipoProducto, @PrecioCompra, @PrecioVenta, @StockActual, @StockMinimo, @Activo, @UsuarioId, CASE WHEN @Activo = 0 THEN SYSDATETIME() ELSE NULL END
        );
        SET @IdProducto = SCOPE_IDENTITY();
    END
    ELSE
    BEGIN
        UPDATE INV.PRODUCTOS SET 
            CODIGO_BARRAS = @CodigoBarras, 
            NOMBRE = @Nombre, 
            MARCA = @Marca, 
            ID_GENERO = @IdGenero, 
            ID_ORIGEN = @IdOrigen, 
            ID_CONCENTRACION = @IdConcentracion, 
            ML = @Ml,
            FECHA_VENCIMIENTO = @FechaVencimiento,
            ID_CATEGORIA = @IdCategoria, 
            TIPO_PRODUCTO = @TipoProducto, 
            PRECIO_COMPRA = @PrecioCompra, 
            PRECIO_VENTA = @PrecioVenta, 
            STOCK_ACTUAL = @StockActual, 
            STOCK_MINIMO = @StockMinimo, 
            ACTIVO = @Activo, 
            FECHA_DESACTIVACION = CASE WHEN ACTIVO = 1 AND @Activo = 0 THEN SYSDATETIME() WHEN @Activo = 1 THEN NULL ELSE FECHA_DESACTIVACION END
        WHERE ID_PRODUCTO = @IdProducto;
    END
    COMMIT TRANSACTION;
    SELECT * FROM INV.V_PRODUCTOS_DETALLE WHERE ID_PRODUCTO = @IdProducto;
END;

